e window and check the console</p>\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/hooks/useOnwindowResize"}'), ('"usePersistedState"', '"hooks"', '"react"', '{"component/MyComponent.jsx": "import usePersistedState from \"../hook/usePersistedState\";\r\n\r\nconst MyComponent = ({ name }) => {\r\n  const [val, setVal] = usePersistedState(name, 10);\r\n  return (\r\n    <input\r\n      value={val}\r\n      onChange={(e) => {\r\n        setVal(e.target.value);\r\n      }}\r\n    />\r\n  );\r\n};\r\n\r\nexport default MyComponent;\r\n", "hook/usePersistedState.js": "import { useState, useRef, useEffect } from \"react\";\r\n\r\nconst usePersistedState = (name, defaultValue) => {\r\n  const [value, setValue] = useState(defaultValue);\r\n  const nameRef = useRef(name);\r\n\r\n  useEffect(() => {\r\n    try {\r\n      const storedValue = localStorage.getItem(name);\r\n      if (storedValue !== null) setValue(storedValue);\r\n      else localStorage.setItem(name, defaultValue);\r\n    } catch {\r\n      setValue(defaultValue);\r\n    }\r\n  }, []);\r\n\r\n  useEffect(() => {\r\n    try {\r\n      localStorage.setItem(nameRef.current, value);\r\n    } catch {}\r\n  }, [value]);\r\n\r\n  useEffect(() => {\r\n    const lastName = nameRef.current;\r\n    if (name !== lastName) {\r\n      try {\r\n        localStorage.setItem(name, value);\r\n        nameRef.current = name;\r\n        localStorage.removeItem(lastName);\r\n      } catch {}\r\n    }\r\n  }, [name]);\r\n\r\n  return [value, setValue];\r\n};\r\n\r\nexport default usePersistedState;\r\n", "package.json": "{\n  \"name\": \"stackblitz-starters-rzbtlt\",\n  \"version\": \"0.0.0\",\n  \"private\": true,\n  \"dependencies\": {\n    \"react\": \"18.2.0\",\n    \"react-dom\": \"18.2.0\"\n  },\n  \"scripts\": {\n    \"start\": \"react-scripts start\",\n    \"build\": \"react-scripts build\",\n    \"test\": \"react-scripts test --env=jsdom\",\n    \"eject\": \"react-scripts eject\"\n  },\n  \"devDependencies\": {\n    \"react-scripts\": \"latest\"\n  }\n}", "public/index.html": "<div id=\"app\"></div>", "src/App.js": "import React from ''react'';\nimport MyComponent from \"../component/MyComponent\";\nimport { useState } from \"react\";\nimport \"./style.css\";\n\nexport default function App() {\n  const [name, setName] = useState(\"my-value\");\n  return (\n    <div className=\"App\">\n      <h1>React usePersistedState hook</h1>\n      <MyComponent name={name} />\n      <input\n        value={name}\n        onChange={(e) => {\n          setName(e.target.value);\n        }}\n      />\n    </div>\n  );\n}\n", "src/style.css": "* {\n  box-sizing: border-box;\n}\n\nbody {\n  margin: 0;\n  padding: 1rem;\n  font-family: system-ui, sans-serif;\n  color: black;\n  background-color: white;\n}\n\nh1 {\n  font-weight: 800;\n  font-size: 1.5rem;\n}\n"}', '{"react": "18.2.0", "react-dom": "18.2.0"}', '{"original_path": "component/react/hooks/usePersistedState"}');